import{_ as e,o as r,c as l,ag as h}from"./chunks/framework.ETe_P6d1.js";const u=JSON.parse('{"title":"开平立园泮文楼建筑考察与文化遗产研究","description":"","frontmatter":{"title":"开平立园泮文楼建筑考察与文化遗产研究"},"headers":[],"relativePath":"reports/陶楚洁/陶楚洁_陶楚洁_开平立园泮文楼建筑考察与文化遗产研究.md","filePath":"reports/陶楚洁/陶楚洁_陶楚洁_开平立园泮文楼建筑考察与文化遗产研究.md"}'),i={name:"reports/陶楚洁/陶楚洁_陶楚洁_开平立园泮文楼建筑考察与文化遗产研究.md"};function t(o,a,n,p,d,s){return r(),l("div",null,[...a[0]||(a[0]=[h('<h1 id="开平立园泮文楼建筑考察与文化遗产研究" tabindex="-1">开平立园泮文楼建筑考察与文化遗产研究 <a class="header-anchor" href="#开平立园泮文楼建筑考察与文化遗产研究" aria-label="Permalink to &quot;开平立园泮文楼建筑考察与文化遗产研究&quot;">​</a></h1><h1 id="课程名称" tabindex="-1">课程名称： <a class="header-anchor" href="#课程名称" aria-label="Permalink to &quot;课程名称：&quot;">​</a></h1><h1 id="课程负责人" tabindex="-1">课程负责人： <a class="header-anchor" href="#课程负责人" aria-label="Permalink to &quot;课程负责人：&quot;">​</a></h1><h1 id="实习日期" tabindex="-1">实习日期： <a class="header-anchor" href="#实习日期" aria-label="Permalink to &quot;实习日期：&quot;">​</a></h1><h1 id="学生所在学院" tabindex="-1">学生所在学院： <a class="header-anchor" href="#学生所在学院" aria-label="Permalink to &quot;学生所在学院：&quot;">​</a></h1><h1 id="专业或班级" tabindex="-1">专业或班级： <a class="header-anchor" href="#专业或班级" aria-label="Permalink to &quot;专业或班级：&quot;">​</a></h1><h1 id="学生姓名" tabindex="-1">学生姓名： <a class="header-anchor" href="#学生姓名" aria-label="Permalink to &quot;学生姓名：&quot;">​</a></h1><h1 id="学生学号" tabindex="-1">学生学号： <a class="header-anchor" href="#学生学号" aria-label="Permalink to &quot;学生学号：&quot;">​</a></h1><h1 id="带队教师" tabindex="-1">带队教师： <a class="header-anchor" href="#带队教师" aria-label="Permalink to &quot;带队教师：&quot;">​</a></h1><h1 id="教务处制" tabindex="-1">教务处制 <a class="header-anchor" href="#教务处制" aria-label="Permalink to &quot;教务处制&quot;">​</a></h1><h1 id="专业调研报告内容" tabindex="-1">专业调研报告内容 <a class="header-anchor" href="#专业调研报告内容" aria-label="Permalink to &quot;专业调研报告内容&quot;">​</a></h1><h3 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h3><p>我们在学校的组织下对开平立园进行了调研。本研究主要以开平立园核心建筑之一泮文楼为研究对象，通过现场调研、文献梳理与比较分析，从建筑语言、材料构造、空间秩序及遗产保护四个维度，分析近代侨乡建筑的建造手法和保护方向。</p><p>研究发现，泮文楼的“中西合璧”建筑手法呈现“功能适配优先于形式模仿、空间组织映射家族观念”的特征，其在多个方面的融合创新都展现出了近代华侨建筑的文化智慧。</p><p>当前保护实践在保存物质载体的同时，面临“生活记忆缺失、叙事趋于单一”的挑战。许多有着优秀建筑手法没有得到传承，宣传方式老套，很难引起大家的注意。我认为遗产保护应该从“静态保存”走向“记忆激活”，构建包含“场景复原、智慧可视化、社区参与”的灵活传承体系。</p><h1 id="关键词" tabindex="-1">关键词： <a class="header-anchor" href="#关键词" aria-label="Permalink to &quot;关键词：&quot;">​</a></h1><hr><h3 id="一、研究背景与问题提出" tabindex="-1">一、研究背景与问题提出 <a class="header-anchor" href="#一、研究背景与问题提出" aria-label="Permalink to &quot;一、研究背景与问题提出&quot;">​</a></h3><p>开平碉楼与村落作为世界文化遗产，是近代华侨文化的重要物质见证。</p><p>现有研究多集中于防御性突出的碉楼，而立园泮文楼为代表的中型居住建筑，则是更加直接对展现了华侨的日常生活、家庭伦理与广东的气候环境。这些建筑是研究文化融合内在机制的珍贵样本，也是比对中西文化差异的桥梁。</p><p>泮文楼由旅美华侨谢维文于 20 世纪 20 年代建造，与泮立楼对称并置，共同构成立园居住核心。与常见强调防御的碉楼不同，泮文楼的核心诉求在于宜居性、家族认同与文化适应融合。</p><p>当前对“中西合璧”的讨论，多停留于风格元素的辨识与罗列，缺乏对其背后逻辑的系统剖析。为此，老师专门带领同学亲自去调研。我们在调研过程中听了很多讲解，深入了解了该建筑群的特色。本研究主要聚焦泮文楼，目的在于回应以下问题：</p><p>其一，明明中国与西方的气候存在差异，为什么西方的建筑元素可以适应中国广东的气候条件？</p><p>其二，其材料与构造如何体现技术移植的本土化创新？</p><p>其三，其空间秩序如何具体承载家族伦理与跨洋记忆？</p><p>其四，作为文化遗产，其当前保护实践在延续精神方面存在哪些局限，未来我们应该怎么改？</p><hr><h3 id="二、功能导向的建筑语言" tabindex="-1">二、功能导向的建筑语言 <a class="header-anchor" href="#二、功能导向的建筑语言" aria-label="Permalink to &quot;二、功能导向的建筑语言&quot;">​</a></h3><p>泮文楼的建筑语言，体现了清晰的理性思维：外来形制与本土习俗的融合，始终以解决实际问题为出发点。</p><p>在调研过程中，我们发现立面构图上建筑采用了古罗马多立克柱式形成环绕敞廊，和我们教科书上的西方柱子非常相似。而这一选择并非单纯追求“西洋风”的美感，而是充分考虑了岭南的气候特征。</p><p>广东的夏季潮湿又炎热，而敞廊则可以在剧烈的阳光下形成有效的阴影区，降低了外墙温度；其开敞的柱廊促进了空气流通，与内部天井共同构成通风系统，让住在室内的人感觉更加清凉。这种设计源于热带殖民建筑的经验，在泮文楼中被巧妙地用于应对本地湿热气候。这就是西洋设计在中国的巧妙融合。</p><p>而该建筑也并不是完全抛弃了东方的古典建筑。屋顶就严格遵循岭南民居形制，采用绿琉璃瓦歇山顶。深远的出檐与特定的坡度，是针对多雨环境的经验性构造，不但美观，而且很实用。西式柱廊与中式屋顶的“嫁接”，在视觉上形成冲突与美感，给人一种完全不一样的视觉体验。这是一次中西文化的成功交融。而在功能上他们则共同服务于建筑和人，成功实现了“形式追随气候”。</p><hr><h3 id="三、材料、构造与本土智慧" tabindex="-1">三、材料、构造与本土智慧 <a class="header-anchor" href="#三、材料、构造与本土智慧" aria-label="Permalink to &quot;三、材料、构造与本土智慧&quot;">​</a></h3><p>泮文楼的建造是近代工业技术与地方传统工艺的一次创造性结合，体现出了华侨的智慧。</p><p>建筑采用钢筋混凝土框架结构。这一当时先进的技术由华侨引入。它不仅增强了建筑的耐久性与抗震抗风性能，更重要的是解放了内部空间。非承重的墙体使得平面布局得以根据现代生活需求灵活划分，满足了那个时期新兴中产多子女家庭对独立卧室、书房等功能空间的追求。</p><p>在围护体系上，建造者则回归本土。外墙采用黄泥混合石灰抹面，这种材料具有良好的热惰性。这种设计在岭南地区能有效隔热；屋面覆盖本地烧制的绿琉璃瓦，其搭接方式与排水坡度沿用传统工艺。这两种工艺都是古代岭南地区人民所经过不断实验和探索之后发现的技巧。这种“内核现代，表皮传统”的策略，既利用了新技术优势，又发挥了地方材料的经济性与气候适应性，体现了设计师高度的务实理性。</p><p>同时，建筑的构造细节处处体现对环境的回应。复合通风系统利用热压与风压促进空气流动，多重隔热设计有效阻隔太阳，完整的防潮排水体系则是用于应对多雨潮湿环境。这些构造并非孤立存在，而是一个协同工作的有机整体，展现了侨乡工匠在吸收外来技术后，进行的本土化改良与集成创新。其背后是深厚的建造智慧。</p><hr><h3 id="四、空间秩序与场所精神" tabindex="-1">四、空间秩序与场所精神 <a class="header-anchor" href="#四、空间秩序与场所精神" aria-label="Permalink to &quot;四、空间秩序与场所精神&quot;">​</a></h3><p>泮文楼的空间深刻映射了近代广东华侨家族复杂的情感世界与身份诉求。</p><p>广东家庭一个很大的特点就是兄弟很多，并且大家庭的妻子也很多。泮文楼与泮立楼就是这样的一对兄弟楼，它呈现出严格的东西对称布局。这一设计极具象征意义。它不仅是功能上的便利连接，更是“兄弟同心、手足相连”的家族伦理在空间上的直观体现。</p><p>建筑内部遵循中轴对称，空间序列清晰：首层为客厅、茶室等对外空间，用于社交与彰显体面；二层及以上为卧室、书房等私密空间。这种“前公后私、下动上静”的垂直分区，既承袭了传统礼制观念，又适应了对私密性与舒适性的现代追求，是伦理秩序与现代生活理念的折衷。</p><p>泮文楼的“场所精神”随时代变迁而流转。</p><p>建造初期，它是谢维文家族荣耀与乡愁的容器。成为文化遗产后，其场所精神转向为宏大的“侨乡历史叙事”。建筑被改造为展览馆，原有生活场景被移除。这一转变赋予了其公共教育价值，但也不可避免地让他失去了生活感。游客走进去可以看见这栋建筑的历史，却看不见这个家庭的历史，并没有很好地起到文化传承的价值。仅仅是建筑得到了活力，而精神没有被延伸。大多数游客都只是走马观花的，看完了这个建筑并没有真正感受到华侨的乡愁。</p><hr><h3 id="五、批判与重构" tabindex="-1">五、批判与重构 <a class="header-anchor" href="#五、批判与重构" aria-label="Permalink to &quot;五、批判与重构&quot;">​</a></h3><p>作为世界文化遗产的组成部分，泮文楼的保护在物质保存层面成效显著，但在价值阐释与精神传承方面，仍有深化空间。</p><p>当前保护模式主要是将生活建筑改为博物馆。在保护建筑的同时，展出这个建筑的历史文化，并使其免于荒废。通过基础展览向公众开放，实现了文化遗产的社会共享。</p><p>然而，其局限也很明显：</p><p>首先，建筑内部生活痕迹的清除使其成为一个“精美的空壳”，参观者难以感知其作为“家”的真实氛围与使用方式。</p><p>其次，其卓越的气候适应性设计与建造智慧未得到有效阐释。游客的认知多停留在风格表面。大家在参观的时候只能感受到好漂亮好华丽，并不能感受到他很有用。</p><p>最后，叙事偏向宏大历史，与建造者、居住者具体的生命故事联结较弱，缺乏打动人心的个体维度。</p><p>为突破“静态保存”的局限，实现从“保存物”到“延续魂”的升华，未来保护可探索以下路径：</p><p>第一，有限度的场景复原与沉浸叙事：选择一至两个核心房间，依据考据复原 20 世纪 30 年代华侨家庭的典型生活场景。运用声音、光影，营造多感官沉浸体验。讲故事的不再是讲解员，而是空间本身。</p><p>第二，随着科技的不断发展，VR 等等技术也在蒸蒸日上。我们可以利用这些技术，生动展示其通风、隔热、排水系统的运作原理，将专业的建筑知识转化为通俗易懂的科普内容。</p><p>第三，我们可以让一些华侨来分享自己的生活，产生情感上的共鸣。</p><p>第四，也是和我们紧密相连的一点，那就是可以让学习设计的学生来参与文创设计，让建筑焕发新生。</p><hr><h3 id="六、结论" tabindex="-1">六、结论 <a class="header-anchor" href="#六、结论" aria-label="Permalink to &quot;六、结论&quot;">​</a></h3><p>开平立园的价值远不止于“中西合璧”的视觉特征，更在于其背后功能主导的融合逻辑、技术本土化的创新智慧、以及空间承载的情感。它标志着侨乡建筑从对外来形式的简单模仿，走向了自主创造。</p><p>当前，以泮文楼为代表的侨乡建筑遗产保护，正处于从“物质存续”向“价值再生”转型的关键阶段。未来的保护应在确保物质载体安全的前提下，致力于挖掘其深层智慧，激活其情感共鸣。</p><hr><h3 id="附录-调研记录" tabindex="-1">附录：调研记录 <a class="header-anchor" href="#附录-调研记录" aria-label="Permalink to &quot;附录：调研记录&quot;">​</a></h3><h4 id="_6-1-摄影记录" tabindex="-1">6.1 摄影记录 <a class="header-anchor" href="#_6-1-摄影记录" aria-label="Permalink to &quot;6.1 摄影记录&quot;">​</a></h4><p>本报告共插入 4 张现场照片，分别展示：</p><ul><li>图 1：立园泮文楼简介</li><li>图 2：泮文楼古罗马多立克柱式</li><li>图 3：泮文楼外外观构造</li><li>图 4：泮文楼三层平面图</li></ul><h4 id="_6-2-参考文献" tabindex="-1">6.2 参考文献 <a class="header-anchor" href="#_6-2-参考文献" aria-label="Permalink to &quot;6.2 参考文献&quot;">​</a></h4><ol><li>《开平碉楼与村落》，张国雄、谭金花，广东人民出版社，2015</li><li>《开平县志》，开平市地方志编纂委员会，中华书局，2002</li><li>《立园泮文楼装饰艺术的跨文化解读》，林晓霞、陈志华，建筑学报，2018</li><li>《侨乡碉楼空间伦理的家族隐喻一一以开平立园“兄弟楼”为例》，刘拓，华南理工大学学报(社会科学版)，2020</li><li>《开平碉楼防御性构造的现代化转型》，吴玉娴，古建园林技术，2016</li><li>《开平立园建筑装饰的岭南基因与海外移植研究》，谭晓薇，华南理工大学，2019</li><li>《侨乡建筑中的“炫耀性消费”现象研究》，陈国栋，香港中文大学，2014</li></ol><h1 id="报告撰写人" tabindex="-1">报告撰写人： <a class="header-anchor" href="#报告撰写人" aria-label="Permalink to &quot;报告撰写人：&quot;">​</a></h1><h1 id="报告完成时间" tabindex="-1">报告完成时间： <a class="header-anchor" href="#报告完成时间" aria-label="Permalink to &quot;报告完成时间：&quot;">​</a></h1><h1 id="字数统计" tabindex="-1">字数统计： <a class="header-anchor" href="#字数统计" aria-label="Permalink to &quot;字数统计：&quot;">​</a></h1><hr>',73)])])}const _=e(i,[["render",t]]);export{u as __pageData,_ as default};
